import { useState, useMemo } from "react";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { useAllMembershipOrders, useArchiveMembershipOrders, MembershipOrder } from "@/hooks/useMembershipOrders";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Crown, DollarSign, Users, TrendingUp, Search, Archive, Loader2, Eye } from "lucide-react";
import { format } from "date-fns";
import { toast } from "sonner";

const statusVariant = (status: string) => {
  switch (status) {
    case "success": return "default";
    case "pending": return "secondary";
    case "cancelled": return "outline";
    case "failed": return "destructive";
    default: return "outline";
  }
};

const statusLabel = (status: string) => {
  switch (status) {
    case "success": return "✅ 成功";
    case "pending": return "⏳ 待处理";
    case "cancelled": return "❌ 已取消";
    case "failed": return "⚠️ 失败";
    default: return status;
  }
};

const AdminMembershipOrders = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { data: orders = [], isLoading } = useAllMembershipOrders();
  const archiveMutation = useArchiveMembershipOrders();
  const [statusFilter, setStatusFilter] = useState<string>("all");
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [detailOrder, setDetailOrder] = useState<MembershipOrder | null>(null);
  const filtered = useMemo(() => {
    return orders.filter(o => {
      if (statusFilter !== "all" && o.status !== statusFilter) return false;
      if (searchQuery && !o.user_id.includes(searchQuery) && !o.product_id.includes(searchQuery) && !(o.apple_transaction_id || "").includes(searchQuery)) return false;
      return true;
    });
  }, [orders, statusFilter, searchQuery]);

  const stats = useMemo(() => {
    const total = orders.length;
    const success = orders.filter(o => o.status === "success").length;
    const revenue = orders.filter(o => o.status === "success").reduce((sum, o) => sum + (o.amount || 0), 0);
    const uniqueUsers = new Set(orders.filter(o => o.status === "success").map(o => o.user_id)).size;
    return { total, success, revenue, uniqueUsers };
  }, [orders]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === filtered.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(filtered.map(o => o.id)));
    }
  };

  const handleArchive = () => {
    if (selectedIds.size === 0) return;
    if (!window.confirm(`确认归档（删除）${selectedIds.size} 条订单？此操作不可恢复。`)) return;
    
    archiveMutation.mutate(Array.from(selectedIds), {
      onSuccess: () => {
        toast.success(`已归档 ${selectedIds.size} 条订单`);
        setSelectedIds(new Set());
      },
      onError: () => {
        toast.error("归档失败");
      },
    });
  };

  if (isLoading) {
    return (
      <div className="space-y-4 p-4">
        <Skeleton className="h-8 w-48" />
        <div className="grid grid-cols-4 gap-4">
          {[1, 2, 3, 4].map(i => <Skeleton key={i} className="h-24" />)}
        </div>
        <Skeleton className="h-96" />
      </div>
    );
  }

  return (
    <div className="space-y-6 p-4">
      <h1 className="text-2xl font-bold flex items-center gap-2">
        <Crown className="h-6 w-6 text-primary" />
        会员订单管理
      </h1>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <Card>
          <CardContent className="pt-4 pb-4">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <TrendingUp className="h-4 w-4" /> 总订单
            </div>
            <p className="text-2xl font-bold">{stats.total}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-4">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Crown className="h-4 w-4" /> 成功订单
            </div>
            <p className="text-2xl font-bold text-primary">{stats.success}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-4">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <DollarSign className="h-4 w-4" /> 总收入
            </div>
            <p className="text-2xl font-bold">${stats.revenue.toFixed(2)}</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-4 pb-4">
            <div className="flex items-center gap-2 text-sm text-muted-foreground mb-1">
              <Users className="h-4 w-4" /> 付费用户
            </div>
            <p className="text-2xl font-bold">{stats.uniqueUsers}</p>
          </CardContent>
        </Card>
      </div>

      {/* Filters + Archive Action */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="搜索用户ID / 产品ID / 交易ID..."
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="pl-9"
          />
        </div>
        <Select value={statusFilter} onValueChange={setStatusFilter}>
          <SelectTrigger className="w-40">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="all">全部状态</SelectItem>
            <SelectItem value="success">成功</SelectItem>
            <SelectItem value="pending">待处理</SelectItem>
            <SelectItem value="cancelled">已取消</SelectItem>
            <SelectItem value="failed">失败</SelectItem>
          </SelectContent>
        </Select>
        {selectedIds.size > 0 && (
          <Button
            variant="destructive"
            size="sm"
            onClick={handleArchive}
            disabled={archiveMutation.isPending}
            className="shrink-0"
          >
            {archiveMutation.isPending ? (
              <Loader2 className="h-4 w-4 mr-2 animate-spin" />
            ) : (
              <Archive className="h-4 w-4 mr-2" />
            )}
            归档 ({selectedIds.size})
          </Button>
        )}
      </div>

      {/* Orders Table */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">订单列表 ({filtered.length})</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead className="w-10">
                    <Checkbox
                      checked={filtered.length > 0 && selectedIds.size === filtered.length}
                      onCheckedChange={toggleSelectAll}
                    />
                  </TableHead>
                  <TableHead>时间</TableHead>
                  <TableHead>用户ID</TableHead>
                  <TableHead>产品</TableHead>
                  <TableHead>金额</TableHead>
                  <TableHead>状态</TableHead>
                  <TableHead>平台</TableHead>
                  <TableHead>Apple交易ID</TableHead>
                  <TableHead>错误信息</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {filtered.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={9} className="text-center text-muted-foreground py-8">
                      暂无订单记录
                    </TableCell>
                  </TableRow>
                ) : (
                  filtered.map(order => (
                    <TableRow 
                      key={order.id} 
                      className={`cursor-pointer hover:bg-muted/70 ${selectedIds.has(order.id) ? "bg-muted/50" : ""}`}
                      onClick={() => setDetailOrder(order)}
                    >
                      <TableCell onClick={e => e.stopPropagation()}>
                        <Checkbox
                          checked={selectedIds.has(order.id)}
                          onCheckedChange={() => toggleSelect(order.id)}
                        />
                      </TableCell>
                      <TableCell className="whitespace-nowrap text-xs">
                        {format(new Date(order.created_at), "yyyy-MM-dd HH:mm")}
                      </TableCell>
                      <TableCell 
                        className="font-mono text-xs max-w-[120px] truncate cursor-pointer text-primary hover:underline" 
                        title={order.user_id}
                        onClick={(e) => { e.stopPropagation(); navigate(`/user/${order.user_id}`); }}
                      >
                        {order.user_id.slice(0, 8)}...
                      </TableCell>
                      <TableCell>{order.product_id}</TableCell>
                      <TableCell>
                        {order.amount ? `$${order.amount}` : "-"}
                      </TableCell>
                      <TableCell>
                        <Badge variant={statusVariant(order.status) as any}>
                          {statusLabel(order.status)}
                        </Badge>
                      </TableCell>
                      <TableCell>{order.platform || "-"}</TableCell>
                      <TableCell className="font-mono text-xs max-w-[120px] truncate" title={order.apple_transaction_id || ""}>
                        {order.apple_transaction_id || "-"}
                      </TableCell>
                      <TableCell className="text-xs text-destructive max-w-[150px] truncate" title={order.error_message || ""}>
                        {order.error_message || "-"}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {/* Order Detail Dialog */}
      <Dialog open={!!detailOrder} onOpenChange={(open) => !open && setDetailOrder(null)}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Eye className="h-5 w-5" /> 订单详情
            </DialogTitle>
          </DialogHeader>
          {detailOrder && (
            <div className="space-y-3 text-sm">
              <DetailRow label="订单ID" value={detailOrder.id} mono />
              <DetailRow label="创建时间" value={format(new Date(detailOrder.created_at), "yyyy-MM-dd HH:mm:ss")} />
              <DetailRow label="更新时间" value={format(new Date(detailOrder.updated_at), "yyyy-MM-dd HH:mm:ss")} />
              <DetailRow 
                label="用户ID" 
                value={detailOrder.user_id} 
                mono 
                action={<Button variant="link" size="sm" className="h-auto p-0 text-xs" onClick={() => { setDetailOrder(null); navigate(`/user/${detailOrder.user_id}`); }}>查看用户</Button>}
              />
              <DetailRow label="产品ID" value={detailOrder.product_id} />
              <DetailRow label="金额" value={detailOrder.amount ? `$${detailOrder.amount} ${detailOrder.currency || 'USD'}` : "-"} />
              <div className="flex items-center justify-between py-1.5 border-b">
                <span className="text-muted-foreground">状态</span>
                <Badge variant={statusVariant(detailOrder.status) as any}>{statusLabel(detailOrder.status)}</Badge>
              </div>
              <DetailRow label="平台" value={detailOrder.platform || "-"} />
              <DetailRow label="Apple交易ID" value={detailOrder.apple_transaction_id || "-"} mono />
              <DetailRow label="关联餐厅ID" value={detailOrder.restaurant_id || "-"} mono />
              {detailOrder.error_message && (
                <div className="py-1.5 border-b">
                  <span className="text-muted-foreground block mb-1">错误信息</span>
                  <p className="text-destructive text-xs break-all">{detailOrder.error_message}</p>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
};

const DetailRow = ({ label, value, mono, action }: { label: string; value: string; mono?: boolean; action?: React.ReactNode }) => (
  <div className="flex items-center justify-between py-1.5 border-b gap-4">
    <span className="text-muted-foreground shrink-0">{label}</span>
    <div className="flex items-center gap-2 min-w-0">
      <span className={`truncate text-right ${mono ? 'font-mono text-xs' : ''}`} title={value}>{value}</span>
      {action}
    </div>
  </div>
);

export default AdminMembershipOrders;
